SET NOCOUNT ON;
BEGIN TRANSACTION;
IF OBJECT_ID(N'dbo.well_material_stats_20251231', N'U') IS NOT NULL DROP TABLE dbo.well_material_stats_20251231;
CREATE TABLE dbo.well_material_stats_20251231 (
    id BIGINT IDENTITY(1,1) NOT NULL PRIMARY KEY,
    receive_time NVARCHAR(50) NULL,
    entrust_id NVARCHAR(100) NOT NULL,
    std_entrust_id NVARCHAR(100) NULL,
    sample_type NVARCHAR(255) NULL,
    client_name NVARCHAR(255) NULL,
    sample_num INT NULL,
    finish_status NVARCHAR(100) NULL
);
COMMIT TRANSACTION;
SELECT COUNT(1) AS imported_count FROM dbo.well_material_stats_20251231;